using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using System.IO;
using System.Threading.Tasks;
using System;
using System.Collections.Generic;
using Microsoft.AspNetCore.Http; // Needed for IFormFile

namespace YourProjectName.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class UploadController : ControllerBase
    {
        private readonly IWebHostEnvironment _webHostEnvironment;

        public UploadController(IWebHostEnvironment webHostEnvironment)
        {
            _webHostEnvironment = webHostEnvironment;
        }

        [HttpPost]
        public async Task<IActionResult> Post([FromForm] List<IFormFile> files)
        {
            if (files == null || files.Count == 0)
            {
                return BadRequest("No files received. Please provide one or more files to upload.");
            }

            var uploadedFilePaths = new List<string>();
            var uploadsDirectory = Path.Combine(_webHostEnvironment.WebRootPath, "uploads");

            // Ensure the uploads directory exists
            if (!Directory.Exists(uploadsDirectory))
            {
                Directory.CreateDirectory(uploadsDirectory);
            }

            foreach (var file in files)
            {
                if (file.Length == 0)
                {
                    // Optionally skip or log empty files
                    continue; 
                }

                try
                {
                    // Generate a unique file name to prevent overwriting existing files
                    var fileExtension = Path.GetExtension(file.FileName);
                    var uniqueFileName = $"{Guid.NewGuid()}{fileExtension}";
                    var filePath = Path.Combine(uploadsDirectory, uniqueFileName);

                    // Save the file to the server's file system
                    using (var stream = new FileStream(filePath, FileMode.Create))
                    {
                        await file.CopyToAsync(stream);
                    }

                    // Construct the URL-friendly path to be returned
                    // This assumes your web application is configured to serve static files from wwwroot
                    var relativeWebPath = $"/uploads/{uniqueFileName}";
                    uploadedFilePaths.Add(relativeWebPath);
                }
                catch (Exception ex)
                {
                    // In a real application, you would log this exception (e.g., using ILogger)
                    // and potentially return a more specific error for the failed file.
                    // For simplicity, we return a general server error.
                    return StatusCode(500, $"An error occurred during upload of {file.FileName}: {ex.Message}");
                }
            }

            if (uploadedFilePaths.Count == 0 && files.Count > 0)
            {
                return StatusCode(500, "No files were successfully uploaded due to an unexpected issue.");
            }

            // Return the list of paths for the successfully uploaded files
            return Ok(uploadedFilePaths);
        }
    }
